SELECT i.*, ord.member_nm AS order_nm, ite.prod_nm AS order_item_nm, ste.site_nm AS site_nm, cd_sit.code_label AS settle_item_type_cd_nm FROM st_settle_item i LEFT JOIN od_order ord ON ord.order_id = i.order_id LEFT JOIN od_order_item ite ON ite.order_item_id = i.order_item_id LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN sy_code cd_sit ON cd_sit.code_grp = 'SETTLE_ITEM_TYPE' AND cd_sit.code_value = i.settle_item_type_cd
ORDER BY i.settle_item_id ASC ORDER BY i.settle_item_id DESC ORDER BY i.order_date ASC ORDER BY i.order_date DESC ORDER BY i.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT i.*, ord.member_nm AS order_nm, ite.prod_nm AS order_item_nm, ste.site_nm AS site_nm, cd_sit.code_label AS settle_item_type_cd_nm FROM st_settle_item i LEFT JOIN od_order ord ON ord.order_id = i.order_id LEFT JOIN od_order_item ite ON ite.order_item_id = i.order_item_id LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN sy_code cd_sit ON cd_sit.code_grp = 'SETTLE_ITEM_TYPE' AND cd_sit.code_value = i.settle_item_type_cd
ORDER BY i.settle_item_id ASC ORDER BY i.settle_item_id DESC ORDER BY i.order_date ASC ORDER BY i.order_date DESC ORDER BY i.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

